// Formato Goldennet: CSV ',' con decimal punto y fechas ISO (aaaa-mm-dd).
// Columnas: fecha,asiento,cuenta,concepto,debe,haber,documento,nif.
// Fuente: asientos+apuntes reales de Kontia. Validar con una importación de prueba antes de uso masivo.
const rows = $('Leer Apuntes PostgreSQL').all().map(i => i.json);
const body = $('Webhook').first().json.body || {};
const ejercicio = String(body.ejercicio || new Date().getFullYear());
const fmt2 = (n) => (Number(n) || 0).toFixed(2);
const fIso = (iso) => String(iso || '').substring(0, 10);
const clean = (s, len) => String(s || '').replace(/[",\r\n]/g, ' ').substring(0, len);

const lineas = ['fecha,asiento,cuenta,concepto,debe,haber,documento,nif'];
for (const r of rows) {
  lineas.push([
    fIso(r.fecha), r.asiento, r.cuenta,
    clean(r.concepto, 50), fmt2(r.debe), fmt2(r.haber),
    clean(r.documento, 20), clean(r.nif, 15)
  ].join(','));
}

return [{
  json: {
    success: true,
    total_apuntes: rows.length,
    formato: 'Goldennet',
    csv_content: lineas.join('\r\n'),
    filename: 'kontia_goldennet_' + ejercicio + '.csv'
  }
}];
